package org.apache.camel.component.fix;

import org.apache.camel.AsyncCallback;
import org.apache.camel.Exchange;
import org.apache.camel.support.DefaultAsyncProducer;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

/**
 * FIX producer that sends outbound FIX messages from Camel exchanges.
 */
public class FixProducer extends DefaultAsyncProducer {

    private static final Logger LOG = LoggerFactory.getLogger(FixProducer.class);

    public FixProducer(FixEndpoint endpoint) {
        super(endpoint);
    }

    @Override
    public FixEndpoint getEndpoint() {
        return (FixEndpoint) super.getEndpoint();
    }

    @Override
    public boolean process(Exchange exchange, AsyncCallback callback) {
        try {
            String fixMessage = exchange.getIn().getBody(String.class);
            String sessionId = exchange.getIn().getHeader(FixConstants.FIX_SESSION_ID, String.class);

            if (sessionId == null) {
                sessionId = getEndpoint().getSessionID();
            }

            LOG.debug("Sending FIX message to session {}: {}", sessionId, fixMessage);

            // In a full implementation this would use the QuickFIX/J Session.sendToTarget()
            // or similar API to dispatch the message to the FIX counterparty.
            sendFixMessage(fixMessage, sessionId);

        } catch (Exception e) {
            exchange.setException(e);
        } finally {
            callback.done(true);
        }
        return true;
    }

    /**
     * Sends a FIX message to the specified session.
     *
     * @param  fixMessage the raw FIX message string
     * @param  sessionId  the target FIX session ID
     * @throws Exception  if the message cannot be sent
     */
    protected void sendFixMessage(String fixMessage, String sessionId) throws Exception {
        LOG.debug("FIX message dispatched to session {}", sessionId);
    }

    @Override
    protected void doStart() throws Exception {
        LOG.info("Starting FIX producer for session: {}", getEndpoint().getSessionID());
        super.doStart();
    }

    @Override
    protected void doStop() throws Exception {
        LOG.info("Stopping FIX producer for session: {}", getEndpoint().getSessionID());
        super.doStop();
    }
}

